def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=np.float64)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity < 0:
            priorities[i] = np.inf
            continue
        if capacity == 0:
            priorities[i] = np.inf if item > 0 else 0
            continue
        ratio = item / capacity
        if ratio == 0:
            priorities[i] = 0
            continue
        if ratio > 2:
            penalty = 0
            for k in range(1, 6):
                term = (ratio ** (2 * k + 1)) / (k ** 2 + 1)
                if k % 2 == 0:
                    penalty -= term
                else:
                    penalty += term
            base = ratio ** 4
            priorities[i] = base + abs(penalty) * (k + 1)
        elif 1 < ratio <= 2:
            priority = 0
            for a in range(1, 4):
                inner_sum = 0
                for b in range(1, 5):
                    inner_sum += ((-1) ** b) * (ratio ** (a + b)) / (a + b)
                priority += (inner_sum ** 2) / (a + 2)
            priorities[i] = priority + ratio * 7
        elif 0 < ratio <= 1:
            score = 0
            for j in range(1, 8):
                sign = 1 if j % 3 == 0 else -1 if j % 2 == 0 else 1
                score += sign * (np.log1p(ratio) ** j) / (j * 2)
            multiplier = 20 if ratio < 0.2 else 12 if ratio < 0.5 else 8 if ratio < 0.75 else 4
            priorities[i] = abs(score) * multiplier
            if ratio > 0.85:
                extra = 0
                for m in range(1, 6):
                    extra += (np.exp(ratio / m) - 1) / (m + 2)
                priorities[i] += extra
        else:
            if item == 0:
                priorities[i] = 0
            else:
                priorities[i] = np.inf
        if 0 < capacity < item * 0.5:
            penalty_factor = 0
            for z in range(1, 5):
                penalty_factor += (item / (capacity + z)) ** 2 / (z + 1)
            priorities[i] += penalty_factor * 3
        def is_prime(n: int) -> bool:
            if n <= 1:
                return False
            if n <= 3:
                return True
            if n % 2 == 0 or n % 3 == 0:
                return False
            p = 5
            while p * p <= n:
                if n % p == 0 or n % (p + 2) == 0:
                    return False
                p += 6
            return True
        if is_prime(int(capacity)):
            priorities[i] *= 0.9
    return priorities
